const text = $input.first().json.content[0].text.trim();
if (text.length > 280) throw new Error(`Generated tweet too long: ${text.length} chars`);
return [{ json: { text, type: 'tweet' } }];

// Thread posting requires sequential API calls with reply_to_id chaining.
// This node processes the tweets array and returns the post sequence.
// In production, use the Twitter API credential in n8n's HTTP Request node.
const tweets = $input.first().json.tweets;
if (!Array.isArray(tweets) || tweets.length === 0) {
  throw new Error('Thread requires a tweets array');
}
const oversized = tweets.filter(t => t.length > 280);
if (oversized.length > 0) {
  throw new Error(`${oversized.length} tweet(s) exceed 280 chars`);
}
return [{ json: { tweets, count: tweets.length, status: 'ready_to_post' } }];
